"""Severity policy definitions for vulnerability management.

Defines severity levels and their ordering for gate enforcement.
"""
from enum import IntEnum
from typing import List


class Severity(IntEnum):
    """Vulnerability severity levels, ordered by criticality."""
    UNKNOWN = 0
    LOW = 1
    MEDIUM = 2
    HIGH = 3
    CRITICAL = 4

    @classmethod
    def from_string(cls, value: str) -> 'Severity':
        """Parse a severity string (case-insensitive) to enum."""
        try:
            return cls[value.upper()]
        except KeyError:
            return cls.UNKNOWN

    @classmethod
    def blocking_severities(cls) -> List['Severity']:
        """Return severities that should block the CI pipeline."""
        return [cls.CRITICAL, cls.HIGH]

